# Configuration from environment variables (no hardcoded secrets)
SOURCE_BUCKET = os.environ.get("SOURCE_BUCKET", "")
RESULTS_BUCKET = os.environ.get("RESULTS_BUCKET", "")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN", "")

# Allowlists for validation
ALLOWED_IMAGE_EXTENSIONS = {".jpg", ".jpeg", ".png", ".gif", ".bmp", ".webp", ".tiff"}
ALLOWED_CONTENT_TYPES = {
    "image/jpeg",
    "image/png",
    "image/gif",
    "image/bmp",
    "image/webp",
    "image/tiff",
}
MAX_IMAGE_SIZE_BYTES = 50 * 1024 * 1024  # 50 MB
# Restrict S3 key to safe characters: alphanumeric, hyphens, underscores, dots, slashes
SAFE_KEY_PATTERN = re.compile(r"^[a-zA-Z0-9\-_./]+$")
MAX_KEY_LENGTH = 1024

# Initialize clients outside handler for connection reuse
s3_client = boto3.client("s3")
sns_client = boto3.client("sns")


def validate_s3_key(key: str) -> bool:
    """Validate S3 object key against allowlist pattern to prevent injection."""
    if not key or len(key) > MAX_KEY_LENGTH:
        return False
    if not SAFE_KEY_PATTERN.match(key):
        return False
    # Prevent path traversal
    if ".." in key or key.startswith("/"):
        return False
    # Ensure the key doesn't contain null bytes or other control characters
    if any(ord(c) < 32 for c in key):
        return False
    return True


def validate_file_extension(key: str) -> bool:
    """Check file extension against allowlist of image types."""
    lower_key = key.lower()
    return any(lower_key.endswith(ext) for ext in ALLOWED_IMAGE_EXTENSIONS)


def validate_content_type(content_type: str) -> bool:
    """Validate content type against allowlist."""
    return content_type.lower() in ALLOWED_CONTENT_TYPES


def validate_bucket_name(bucket: str, expected_bucket: str) -> bool:
    """Ensure the bucket matches the expected configured bucket."""
    return bucket == expected_bucket


def sanitize_for_logging(value: str, max_length: int = 200) -> str:
    """Sanitize a value for safe logging - remove control chars and truncate."""
    sanitized = "".join(c for c in value if ord(c) >= 32 and ord(c) != 127)
    if len(sanitized) > max_length:
        sanitized = sanitized[:max_length] + "...[truncated]"
    return sanitized


def send_notification(subject: str, message: str) -> None:
    """Send SNS notification with error handling."""
    if not SNS_TOPIC_ARN:
        logger.warning("SNS_TOPIC_ARN not configured, skipping notification")
        return

    try:
        # Sanitize message content - don't include raw user input in notifications
        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=subject[:100],  # SNS subject limit
            Message=message[:262144],  # SNS message size limit
        )
        logger.info("SNS notification sent successfully")
    except ClientError as e:
        error_code = e.response["Error"]["Code"]
        logger.error("Failed to send SNS notification: %s", error_code)


