def lambda_handler(event, context):
    """
    Main Lambda handler for processing S3 image upload events.
    Triggered by S3 PUT events on the source bucket.
    """
    logger.info("Image processing Lambda invoked")

    # Validate environment configuration
    if not SOURCE_BUCKET or not RESULTS_BUCKET:
        logger.error("Required environment variables SOURCE_BUCKET and RESULTS_BUCKET must be set")
        return {
            "statusCode": 500,
            "body": json.dumps({"error": "Server configuration error"}),
        }

    # Validate event structure
    if not event or "Records" not in event:
        logger.error("Invalid event structure: missing Records")
        return {
            "statusCode": 400,
            "body": json.dumps({"error": "Invalid event structure"}),
        }

    results = []

    for record in event.get("Records", []):
        try:
            # Extract and validate S3 event information
            s3_info = record.get("s3", {})
            bucket_info = s3_info.get("bucket", {})
            object_info = s3_info.get("object", {})

            source_bucket = bucket_info.get("name", "")
            # URL-decode the key (S3 events URL-encode the key)
            raw_key = object_info.get("key", "")
            source_key = urllib.parse.unquote_plus(raw_key)
            object_size = object_info.get("size", 0)

            # Validate source bucket matches expected bucket
            if not validate_bucket_name(source_bucket, SOURCE_BUCKET):
                logger.error(
                    "Unexpected source bucket: %s",
                    sanitize_for_logging(source_bucket),
                )
                results.append(
                    {"key": sanitize_for_logging(source_key), "status": "error", "reason": "invalid bucket"}
                )
                continue

            # Validate S3 key format
            if not validate_s3_key(source_key):
                logger.error(
                    "Invalid S3 key format: %s",
                    sanitize_for_logging(source_key),
                )
                results.append(
                    {"key": sanitize_for_logging(source_key), "status": "error", "reason": "invalid key format"}
                )
                continue

            # Validate file extension
            if not validate_file_extension(source_key):
                logger.warning(
                    "File extension not in allowlist: %s",
                    sanitize_for_logging(source_key),
                )
                results.append(
                    {"key": sanitize_for_logging(source_key), "status": "skipped", "reason": "unsupported file type"}
                )
                continue

            # Validate file size from event metadata
            if object_size > MAX_IMAGE_SIZE_BYTES:
                logger.warning(
                    "File too large (%d bytes): %s",
                    object_size,
                    sanitize_for_logging(source_key),
                )
                results.append(
                    {"key": sanitize_for_logging(source_key), "status": "skipped", "reason": "file too large"}
                )
                continue

            logger.info(
                "Processing image: %s (size: %d bytes)",
                sanitize_for_logging(source_key),
                object_size,
            )

            # Read image from S3
            try:
                response = s3_client.get_object(
                    Bucket=SOURCE_BUCKET,
                    Key=source_key,
                )
            except ClientError as e:
                error_code = e.response["Error"]["Code"]
                if error_code == "NoSuchKey":
                    logger.warning(
                        "Object not found: %s",
                        sanitize_for_logging(source_key),
                    )
                    results.append(
                        {"key": sanitize_for_logging(source_key), "status": "error", "reason": "object not found"}
                    )
                    continue
                elif error_code == "AccessDenied":
                    logger.error(
                        "Access denied reading object: %s",
                        sanitize_for_logging(source_key),
                    )
                    results.append(
                        {"key": sanitize_for_logging(source_key), "status": "error", "reason": "access denied"}
                    )
                    continue
                else:
                    raise

            # Validate content type from S3 metadata
            content_type = response.get("ContentType", "")
            if content_type and not validate_content_type(content_type):
                logger.warning(
                    "Content type not in allowlist: %s for key: %s",
                    sanitize_for_logging(content_type),
                    sanitize_for_logging(source_key),
                )
                results.append(
                    {"key": sanitize_for_logging(source_key), "status": "skipped", "reason": "unsupported content type"}
                )
                continue

            # Validate actual content length
            content_length = response.get("ContentLength", 0)
            if content_length > MAX_IMAGE_SIZE_BYTES:
                logger.warning(
                    "Actual content length too large (%d bytes): %s",
                    content_length,
                    sanitize_for_logging(source_key),
                )
                results.append(
                    {"key": sanitize_for_logging(source_key), "status": "skipped", "reason": "file too large"}
                )
                continue

            # Read image data with size limit enforcement
            image_data = response["Body"].read(MAX_IMAGE_SIZE_BYTES + 1)
            if len(image_data) > MAX_IMAGE_SIZE_BYTES:
                logger.warning(
                    "Image data exceeds maximum size during read: %s",
                    sanitize_for_logging(source_key),
                )
                results.append(
                    {"key": sanitize_for_logging(source_key), "status": "skipped", "reason": "file too large"}
                )
                continue

            # Process the image
            processed_data = process_image(image_data, source_key)

            if processed_data is None:
                logger.error(
                    "Image processing failed for: %s",
                    sanitize_for_logging(source_key),
                )
                results.append(
                    {"key": sanitize_for_logging(source_key), "status": "error", "reason": "processing failed"}
                )
                send_notification(
                    subject="Image Processing Failed",
                    message=f"Failed to process image: {sanitize_for_logging(source_key)}",
                )
                continue

            # Construct result key - use a safe prefix in the results bucket
            # Strip any leading directory from source key for the result
            base_filename = source_key.rsplit("/", 1)[-1] if "/" in source_key else source_key
            result_key = f"processed/{base_filename}"

            # Validate the constructed result key
            if not validate_s3_key(result_key):
                logger.error(
                    "Generated invalid result key: %s",
                    sanitize_for_logging(result_key),
                )
                results.append(
                    {"key": sanitize_for_logging(source_key), "status": "error", "reason": "invalid result key"}
                )
                continue

            # Write processed image to results bucket
            try:
                s3_client.put_object(
                    Bucket=RESULTS_BUCKET,
                    Key=result_key,
                    Body=processed_data,
                    ContentType=content_type if content_type else "application/octet-stream",
                    ServerSideEncryption="aws:kms",
                )
            except ClientError as e:
                error_code = e.response["Error"]["Code"]
                logger.error(
                    "Failed to write result to S3: %s (error: %s)",
                    sanitize_for_logging(result_key),
                    error_code,
                )
                results.append(
                    {"key": sanitize_for_logging(source_key), "status": "error", "reason": "write failed"}
                )
                send_notification(
                    subject="Image Processing Write Failed",
                    message=f"Failed to write processed image for: {sanitize_for_logging(source_key)}",
                )
                continue

            logger.info(
                "Successfully processed and saved: %s -> %s",
                sanitize_for_logging(source_key),
                sanitize_for_logging(result_key),
            )

            results.append(
                {
                    "key": sanitize_for_logging(source_key),
                    "result_key": sanitize_for_logging(result_key),
                    "status": "success",
                }
            )

            # Send success notification
            send_notification(
                subject="Image Processed Successfully",
                message=f"Image processed: {sanitize_for_logging(source_key)} -> {sanitize_for_logging(result_key)}",
            )

        except ClientError as e:
            error_code = e.response["Error"]["Code"]
            logger.error(
                "AWS ClientError processing record: %s",
                error_code,
            )
            results.append({"status": "error", "reason": "aws_client_error"})
        except Exception:
            # Log exception type but not full details which might contain sensitive data
            logger.exception("Unexpected error processing record")
            results.append({"status": "error", "reason": "unexpected_error"})

    success_count = sum(1 for r in results if r.get("status") == "success")
    error_count = sum(1 for r in results if r.get("status") == "error")
    skipped_count = sum(1 for r in results if r.get("status") == "skipped")

    logger.info(
        "Processing complete: %d success, %d errors, %d skipped",
        success_count,
        error_count,
        skipped_count,
    )

    return {
        "statusCode": 200,
        "body": json.dumps(
            {
                "message": "Processing complete",
                "summary": {
                    "success": success_count,
                    "errors": error_count,
                    "skipped": skipped_count,
                },
                "results": results,
            }
        ),
    }